const express = require('express');
const fs = require('fs');
const libxmljs = require('libxmljs-xmldom');

const app = express();
const port = 3000;

app.use(express.json());

app.post('/parseXML', (req, res) => {
    const xmlBuffer = req.body.data; // Assuming you receive the XML as a buffer in the request body

    let parsedXml;
    try {
        parsedXml = libxmljs(xmlBuffer);
    } catch (error) {
        return res.status(400).json({ error: 'Invalid XML' });
    }

    const jsonObject = {}; // Here you can define your object structure to store the configuration settings

    parsedXml.find('your-xml-tag').traverse((element, index) => {
        if (element.name() === 'your-xml-tag') {
            // Extract configuration settings and store them in jsonObject
            jsonObject[element.attr('id')] = element.text();
        }
    });

    res.json(jsonObject);
});

app.listen(port, () => console.log(`Server running at http://localhost:${port}`));